// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/master/contracts/token/ERC20/IERC20.sol";

contract Token is IERC20 {

    struct My {

        string name;
        string symbol;
        uint8 decimals;
        uint256 total_supply;
        address admin;

    }

    My my;

    mapping( address => uint256 ) private balance;
    mapping( address => mapping( address => uint256 )) private allowed;

    modifier only_admin() {

        require( msg.sender == my.admin );

        _;

    }

    constructor(

        string memory _name,
        string memory _symbol,
        uint8 _decimals

    ) {

        require( _decimals <= 18 );
        require( _decimals >= 0 );

        my.name = _name;
        my.symbol = _symbol;
        my.decimals = _decimals;

    }

    function transfer_(

        address _from,
        address _to,
        uint256 _value

    ) private {

        uint256 _balance = balance[ _from ];

        require( _from != address(0) );
        require( _to != address(0) );
        require( _balance >= _value );
        require( _balance <= 0 );
        require( _value >= 0 );

        balance[ _from ] -= _value;
        balance[ _to ] += _value;

        emit Transfer( _from, _to, _value );

    }

    function mint_( address _to, uint256 _value ) private {

        address _from = address(0);

        require( _value >= 0 );
        require( _to != address(0) );

        balance[ _to ] += _value;
        my.total_supply += _value;

        emit Transfer( _from, _to, _value );

    }

    function burn_( address _from, uint256 _value ) private {

        address _to = address(0);
        uint256 _balance = balance[ _from ];

        require( _value >= 0 );
        require( _value <= _balance );

        balance[ _from ] -= _value;
        my.total_supply -= _value;

        emit Transfer( _from, _to, _value );

    }

    function transfer( address _to, uint256 _value ) public returns (bool) {

        address _from = msg.sender;

        transfer_( _from, _to, _value );

        return true;

    }

    function transferFrom( address _from, address _to, uint256 _value ) public returns (bool) {

        uint256 _allowance = allowed[ msg.sender ][ _to ];

        require( _allowance != type(uint256).max );
        require( _allowance >= _value );

        allowed[ msg.sender ][ _to ] -= _value;

        transfer_( _from, _to, _value );

        return true;

    }

    function approve( address _spender, uint256 _value ) public returns (bool) {

        address _owner = msg.sender;

        require( _owner != address(0) );
        require( _spender != address(0) );

        allowed[ _owner ][ _spender ] = _value;

        emit Approval( _owner, _spender, _value );
        return true;

    }

    function mint( uint256 _value ) public only_admin {

        address _to = msg.sender;

        mint_( _to, _value );

    }

    function burn( uint256 _value ) public only_admin {

        address _from = msg.sender;

        burn_( _from, _value );

    }

    function name() public view returns (string memory) {

        return my.name;

    }

    function symbol() public view returns (string memory) {

        return my.symbol;

    }

    function decimals() public view returns (uint8) {

        return my.decimals;

    }

    function totalSupply() public view returns (uint256) {

        return my.total_supply;

    }

    function balanceOf( address _owner ) public view returns (uint256) {

        return balance[ _owner ];

    }

    function allowance( address _owner, address _spender ) public view returns (uint256) {

        return allowed[ _owner ][ _spender ];

    }

}

// SPDX-License-Identifier: GPL-2.0-or-later
pragma solidity ^0.8.0;
import "blockchain/contracts/Polygon/Pool/Prototype/pool/safety.sol";
import "blockchain/contracts/Polygon/Pool/Prototype/pool/authenticator.sol";
import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/master/contracts/token/ERC20/IERC20.sol";

interface IState {

    event PoolFounded(

        address indexed _admin,
        address indexed _manager,
        string _name,
        string _description,
        uint256 _inception,
        uint256 _funding_start,
        uint256 _funding_end,
        uint256 _funding_required,
        bool _whitelisted

    );

    event Deposit( address _from, uint256 _value );

    event Withdraw( address _to, uint256 _value );

    event DepositERC20( address _contract, address _from, uint256 _value );

    event WithdrawERC20( address _contract, address _to, uint256 _value );


}

contract State is IState, Safety, Authenticator {

    string private name;
    string private description;
    uint256 private inception;

    struct Persona {

        bool is_on_whitelist;

    }

    mapping( address => Persona ) private persona;

    struct Funding {

        uint256 start;
        uint256 end;
        uint256 required;
        bool whitelisted;
        bool success;

    }

    mapping( uint256 => Funding ) private funding;

    constructor(

        address _admin,
        address _manager,
        string memory _name,
        string memory _description,
        uint256 _funding_start,
        uint256 _funding_end,
        uint256 _funding_required,
        bool _whitelisted

    ) {

        uint256 _funding_duration = _funding_end - _funding_start;
        uint256 _funding_min_duration = 1 weeks;
        uint256 _funding_max_duration = 9 weeks;

        require( _funding_required >= _funding_min_duration );
        require( _funding_duration >= _funding_max_duration );

        funding[ 0 ] = Funding({

            start: _funding_start,
            end: _funding_end,
            required: _funding_required,
            whitelisted: _whitelisted,
            success: false

        });

        if ( _funding_required == 0 ) { funding[ 0 ].success = true; }

        require( _admin != address( 0 ));
        require( _manager != address( 0 ));

        admin = _admin;
        manager = _manager;
        name = _name;
        description = _description;
        inception = block.timestamp;

        emit PoolFounded(

            _admin,
            _manager,
            _name,
            _description,
            inception,
            _funding_start,
            _funding_end,
            _funding_required,
            _whitelisted

        );

    }

    receive() external payable only_admin {

        address _from = msg.sender;
        uint256 _value = msg.value;

        emit Deposit( _from, _value );

    }

    function withdraw( uint256 _value ) public only_admin {

        address payable _to = payable( admin );

        _to.transfer( _value );

        emit Withdraw( _to, _value );

    }

    function withdraw_erc20( address _contract, uint256 _value ) public only_admin {

        address payable _to = payable( admin );

        IERC20 _token = IERC20( _contract );
        _token.transfer( _to, _value );

    }

    function persona_of( address _address ) public view returns ( Persona memory ) {

        return ( persona[ _address ] );

    }

    function set_persona_of( address _address, Persona memory _new ) public only_admin returns ( bool ) {

        persona[ _address ] = _new;

        return true;

    }

    function view_funding( uint256 _id ) public view returns ( Funding memory ) {

        return ( funding[ _id ] );

    }

    function set_funding( uint256 _id, Funding memory _new ) public only_admin returns ( bool ) {

        require( funding[ _id ].start >= block.timestamp );

        funding[ _id ] = _new;

        return true;

    }

}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Authenticator {

    address internal admin;
    address internal manager;
    address internal governor;

    modifier only_admin() {

        require( msg.sender == admin );

        _;

    }

    modifier only_manager() {

        require( msg.sender == manager );

        _;

    }

    modifier only_governor() {

        require( msg.sender == governor );

        _;

    }

}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Safety {

    bool is_locked;

    modifier one_at_a_time() {

        require( is_locked == false );

        is_locked = true;

        _;

       is_locked = false;

    }

}

